lay=swap';\n    link.rel = 'stylesheet';\n    document.head.appendChild(link);\n}\n\nfunction populateSelects() {\n    [elements.titleFont, elements.subtitleFont, elements.contentFont].forEach(select => {\n        fonts.forEach(font => {\n            const option = document.createElement('option');\n            option.value = font.family;\n            option.textContent = font.name;\n            select.appendChild(option);\n        });\n    });\n}\n\nfunction applyFont(element, fontFamily) {\n    element.style.fontFamily = `'${fontFamily}', sans-serif`;\n}\n\nfunction applyAllFonts() {\n    applyFont(elements.titleText, elements.titleFont.value);\n    applyFont(elements.subtitleText, elements.subtitleFont.value);\n    applyFont(elements.contentText, elements.contentFont.value);\n    updateURL();\n}\n\nfunction applyGlobalStyles() {\n    const lh = elements.lineHeight.value;\n    const ls = elements.letterSpacing.value;\n    \n    document.documentElement.style.setProperty('--line-height', lh);\n    document.documentElement.style.setProperty('--letter-spacing', `${ls}em`);\n    \n    elements.lineHeightValue.textContent = lh;\n    elements.letterSpacingValue.textContent = `${ls}em`;\n    \n    updateURL();\n}\n\nfunction resetLineHeight() {\n    elements.lineHeight.value = defaults.lineHeight;\n    applyGlobalStyles();\n}\n\nfunction resetLetterSpacing() {\n    elements.letterSpacing.value = defaults.letterSpacing;\n    applyGlobalStyles();\n}\n\nfunction updateURL() {\n    const params = new URLSearchParams();\n    params.set('title', elements.titleFont.value);\n    params.set('subtitle', elements.subtitleFont.value);\n    params.set('content', elements.contentFont.value);\n    params.set('lh', elements.lineHeight.value);\n    params.set('ls', elements.letterSpacing.value);\n    \n    history.replaceState(null, '', `${window.location.pathname}?${params.toString()}`);\n}\n\nfunction loadFromURL() {\n    const params = new URLSearchParams(window.location.search);\n   